const express = require('express');
const bodyParser = require('body-parser');
const jwt = require('jsonwebtoken');
const app = express();
const PORT = process.env.PORT || 3000;

app.use(bodyParser.json());

const SECRET_KEY = 'your_secret_key'; // Replace with your actual secret key
const rewards = {
    1: { scoreThreshold: 100, reward: 'Bronze Badge' },
    2: { scoreThreshold: 200, reward: 'Silver Badge' },
    3: { scoreThreshold: 300, reward: 'Gold Badge' },
};

const authenticateToken = (req, res, next) => {
    const token = req.headers['authorization']?.split(' ')[1];
    if (!token) return res.sendStatus(401);
    jwt.verify(token, SECRET_KEY, (err, user) => {
        if (err) return res.sendStatus(403);
        req.user = user;
        next();
    });
};

app.post('/complete-level', authenticateToken, (req, res) => {
    const { level, score, time } = req.body;

    if (!level || typeof score !== 'number' || typeof time !== 'number') {
        return res.status(400).json({ error: 'Invalid input' });
    }

    const reward = Object.values(rewards).find(r => r.scoreThreshold <= score);
    const rewardMessage = reward ? reward.reward : 'No reward earned';

    // Here you would typically save the level completion to a database

    res.json({ message: 'Level completed', reward: rewardMessage });
});

app.post('/claim-reward', authenticateToken, (req, res) => {
    const { level } = req.body;

    if (!level) {
        return res.status(400).json({ error: 'Level is required' });
    }

    // Logic to check if the user is eligible for the reward
    // This would typically involve checking a database

    res.json({ message: 'Reward claimed successfully' });
});

app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});